#[async_trait]
impl<R: LDAPDirectoryProjectionRepository> LDAPDirectoryEventHandler for LDAPDirectoryProjector<R> {

    async fn on_created(&self, event: LDAPDirectoryCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = LDAPDirectoryProjection::new(
            event.id,
            event.name,
            event.display_name,
            event.host,
            event.port,
            event.use_ssl,
            event.use_tls,
            event.bind_dn,
            event.bind_password,
            event.search_base,
            event.search_filter,
            event.attribute_mapping,
            event.sync_enabled,
            event.sync_interval_minutes,
            event.last_sync_at,
            event.last_sync_result,
            event.is_active,
            event.status,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: LDAPDirectoryUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.name = event.name;
            projection.display_name = event.display_name;
            projection.host = event.host;
            projection.port = event.port;
            projection.use_ssl = event.use_ssl;
            projection.use_tls = event.use_tls;
            projection.bind_dn = event.bind_dn;
            projection.bind_password = event.bind_password;
            projection.search_base = event.search_base;
            projection.search_filter = event.search_filter;
            projection.attribute_mapping = event.attribute_mapping;
            projection.sync_enabled = event.sync_enabled;
            projection.sync_interval_minutes = event.sync_interval_minutes;
            projection.last_sync_at = event.last_sync_at;
            projection.last_sync_result = event.last_sync_result;
            projection.is_active = event.is_active;
            projection.status = event.status;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: LDAPDirectoryDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

